 18	import "./nhc-form.css";
 19	import { useOpenShiftVersion } from "copiedFromConsole/hooks/useOpenShiftVersion";
 20	import { Flex, FlexItem, PageSection } from "@patternfly/react-core";
 21	export interface NodeHealthCheckProps {
 22	  title: string;
 23	  name: string;
 24	  nodeHealthCheck: NodeHealthCheck;
 25	  isCreateFlow: boolean;
 26	}
 27	
 28	const LearnMoreLink: React.FC = () => {
 29	  const { t } = useNodeHealthCheckTranslation();
 30	  const [version, loaded, error] = useOpenShiftVersion();
 31	  React.useEffect(() => {
 32	    if (error) {
 33	      console.error(
 34	        `Failed to retrive OCP version for LearnMore link: ${error}`
 35	      );
 36	    }
 37	  }, [error]);
 38	  if (!loaded) {
 39	    return <LoadingInline />;
 40	  }
 41	  if (error) {
 42	    return null;
 43	  }
 44	  const learnMoreLink = `https://docs.openshift.com/container-platform/${version}/nodes/nodes/eco-node-health-check-operator.html`;
 45	  return (
 46	    <a href={learnMoreLink} target="_blank" rel="noopener noreferrer">
 47	      {t("Learn more")} <ExternalLinkAltIcon />
 48	    </a>
 49	  );
 50	};
 51	
 52	const HelpText: React.FC = () => {
 53	  const { t } = useNodeHealthCheckTranslation();
 54	  return (
 55	    <p>
 56	      {t(
 57	        "NodeHealthChecks define a set of criteria and thresholds to determine the health of a node."
 58	      )}{" "}
 59	      &nbsp;
 60	      <LearnMoreLink />
 61	    </p>
 62	  );
 63	};
 64	
 65	const NodeHealthCheckForm__: React.FC<NodeHealthCheckProps> = ({
 66	  name,
 67	  title,
 68	  nodeHealthCheck,
 69	  isCreateFlow,
 70	}) => {
 71	  const { t } = useNodeHealthCheckTranslation();
 72	  const initialValues = React.useMemo(() => {
 73	    return getFormValues(nodeHealthCheck, isCreateFlow);
 74	  }, [isCreateFlow, nodeHealthCheck]);
 75	
 76	  const navigation = useNodeHealthCheckNavigation();
 77	
 78	  const handleSubmit = async (
 79	    values: NodeHealthCheckFormValues,
 80	    actions: FormikHelpers<NodeHealthCheckFormValues>
 81	  ) => {
 82	    try {
 83	      const updatedNodeHealthCheck = getNodeHealthCheck(
 84	        nodeHealthCheck,
 85	        values
 86	      );
 87	      if (isCreateFlow) {
 88	        await k8sCreate({
 89	          model: NodeHealthCheckModel,
 90	          data: updatedNodeHealthCheck,
 91	        });
 92	      } else {
 93	        await k8sUpdate({
 94	          model: NodeHealthCheckModel,
 95	          data: updatedNodeHealthCheck,
 96	          name,
 97	        });
 98	      }
 99	      navigation.gotoDetails(updatedNodeHealthCheck?.metadata?.name);
100	      return true;
101	    } catch (e) {
102	      actions.setStatus({ submitError: e.message });
103	    }
104	  };
105	
106	  return (
107	    <PageSection variant="light">
108	      <Flex
109	        direction={{ default: "column" }}
110	        spaceItems={{ default: "spaceItemsSm" }}
111	        style={{
112	          height: "100%",
113	        }}
114	      >
115	        <FlexItem>
116	          <PageHeading title={title} helpText={<HelpText />} />
117	        </FlexItem>
118	        <FlexItem grow={{ default: "grow" }}>
119	          <Formik
120	            enableReinitialize
121	            initialValues={initialValues}
122	            onSubmit={handleSubmit}
123	            validationSchema={getValidationSchema(t)}
124	            validateOnMount={true}
125	          >
126	            <NodeHealthCheckSyncedEditor
127	              originalNodeHealthCheck={nodeHealthCheck}
128	              handleCancel={() => navigation.goBack()}
129	            />
130	          </Formik>
131	        </FlexItem>
132	      </Flex>
133	    </PageSection>
134	  );
135	};
136	
137	const NodeHealthCheckForm = withFallback(NodeHealthCheckForm__);
138	
139	export default NodeHealthCheckForm;

